  try {
    _logAuthEvent_({
      kind:       'LOGIN_GOOGLE',
      identifier: email,
      user_id:    user.user_id || '',
      ip:         ip,
      ua:         ua,
      ok:         true,
      error_code: 'ok',
      note:       ''
    });
  } catch (_) {}

  const {headers, sh} = _rows(SH_USERS);
  const idx = _findRowIndexBy(sh, 'email', email);
