    const row = sh.getRange(idx,1,1,headers.length).getValues()[0];
    const obj = _rowToObj(headers,row);
    obj.last_login_utc = _iso(_now());
    _updateObj(sh, headers, idx, obj);
  }

  const profile = {
    user_id:   user.user_id,
