  var finalRole    = 'STUDENT';

  if(allowedRoles.indexOf(roleUpper) >= 0){
    // Only ADMIN caller can grant ADMIN or MODERATOR; STUDENT is fine.
    if(roleUpper === 'ADMIN' || roleUpper === 'MODERATOR'){
      if(callerIsAdmin){
        finalRole = roleUpper;
