function ADMIN_setInitialPassword(){
  const username = 'albert01';        // ← change to your target user
  const plain    = 'Change';  // ← temp password

  const sh = _sh(SH_USERS);
  const headers = _headers(sh);
  const idx = _findRowIndexBy(sh,'username',username);
  if(idx<0) throw new Error('User not found: '+username);

  const row = sh.getRange(idx,1,1,headers.length).getValues()[0];
  const obj = _rowToObj(headers,row);

  const salt = _generateSalt();
  const hash = _hashWebSafeSHA256(salt + plain);
  obj.salt = salt;
  obj.password_hash = hash;
  obj.must_change_password = true;

  _updateObj(sh, headers, idx, obj);
  Logger.log('Initial password set for '+username);
}

